// OpenCL kernels for SRAD algorithm
// Compatible with 1D execution model of the provided wrapper.

// Kernel 1: Computes coefficients (C) and differences (N, S, E, W)
__attribute__((kernel)) void srad_kernel(
          write_only float *E_C, 
          write_only float *W_C, 
          write_only float *N_C, 
          write_only float *S_C,
          const float * J_cuda, 
          write_only float * C_cuda, 
          int cols, 
          int rows, 
          float q0sqr) 
{
  int idx = get_global_id(0);
  int total = cols * rows;

  if (idx >= total) return;

  int j = idx % cols;
  int i = idx / cols;

  float jc = J_cuda[idx];

  // Determine neighbor indices with boundary checks
  int idx_n = (i == 0) ? idx : idx - cols;
  int idx_s = (i == rows - 1) ? idx : idx + cols;
  int idx_w = (j == 0) ? idx : idx - 1;
  int idx_e = (j == cols - 1) ? idx : idx + 1;

  float n_val = J_cuda[idx_n];
  float s_val = J_cuda[idx_s];
  float w_val = J_cuda[idx_w];
  float e_val = J_cuda[idx_e];

  float dN = n_val - jc;
  float dS = s_val - jc;
  float dW = w_val - jc;
  float dE = e_val - jc;

  float g2 = 0.0f;
  float l = 0.0f;

  if (jc != 0.0f) {
      g2 = (dN*dN + dS*dS + dW*dW + dE*dE) / (jc * jc);
      l = (dN + dS + dW + dE) / jc;
  }

  float num = (0.5f * g2) - ((1.0f/16.0f) * (l*l));
  float den = 1.0f + (0.25f * l);

  float qsqr = 0.0f;
  if (den != 0.0f) {
      qsqr = num / (den * den);
  }

  float den2 = q0sqr * (1.0f + q0sqr);
  float c = 1.0f;

  if (den2 != 0.0f) {
      float diff = qsqr - q0sqr;
      float ratio = diff / den2;
      c = 1.0f / (1.0f + ratio);
  }

  if (c < 0.0f) c = 0.0f;
  else if (c > 1.0f) c = 1.0f;

  C_cuda[idx] = c;
  E_C[idx] = dE;
  W_C[idx] = dW;
  S_C[idx] = dS;
  N_C[idx] = dN;
}

// Kernel 2: Updates the image J using the computed coefficients and differences
__attribute__((kernel)) void srad2_kernel(
          const float *E_C, 
          const float *W_C, 
          const float *N_C, 
          const float *S_C,	
          float * J_cuda, 
          const float * C_cuda, 
          int cols, 
          int rows, 
          float lambda,
          float q0sqr) 
{
  int idx = get_global_id(0);
  int total = cols * rows;

  if (idx >= total) return;

  int j = idx % cols;
  int i = idx / cols;

  // Neighbor indices
  int idx_n = (i == 0) ? idx : idx - cols;
  int idx_s = (i == rows - 1) ? idx : idx + cols;
  int idx_w = (j == 0) ? idx : idx - 1;
  int idx_e = (j == cols - 1) ? idx : idx + 1;

  float cc = C_cuda[idx];

  // Preserve the specific asymmetry from the original CPU/GPU code:
  // cN = current, cS = south neighbor, cW = current, cE = east neighbor
  float cN = cc;
  float cS = C_cuda[idx_s];
  float cW = cc;
  float cE = C_cuda[idx_e];

  float d_sum = cN * N_C[idx] + cS * S_C[idx] + cW * W_C[idx] + cE * E_C[idx];

  J_cuda[idx] = J_cuda[idx] + 0.25f * lambda * d_sum;
}

// Additional kernels required by the infrastructure

__attribute__((kernel)) void compress_kernel(long d_Ne, float *d_I) {
    int idx = get_global_id(0);
    if (idx < d_Ne) {
        d_I[idx] = log(d_I[idx]) * 255.0f;
    }
}

__attribute__((kernel)) void extract_kernel(long d_Ne, float *d_I) {
    int idx = get_global_id(0);
    if (idx < d_Ne) {
        d_I[idx] = exp(d_I[idx] / 255.0f);
    }
}

__attribute__((kernel)) void prepare_kernel(long d_Ne, float *d_I, float *d_sums, float *d_sums2) {
    int idx = get_global_id(0);
    if (idx < d_Ne) {
        d_sums[idx] = d_I[idx];
        d_sums2[idx] = d_I[idx] * d_I[idx];
    }
}

// Reduction kernel adapted for OpenCL 1D execution with local memory
__attribute__((kernel)) void reduce_kernel(long d_Ne, int d_no, int d_mul, float *d_sums, float *d_sums2) {
    int idx = get_global_id(0);
    int tid = get_local_id(0);
    int gid = get_group_id(0);

    // Use dynamic local array size based on BLOCK_SIZE or a safe max
    float local_sums[BLOCK_SIZE];
    float local_sums2[BLOCK_SIZE];

    // Load data
    if (idx < d_no) {
        local_sums[tid] = d_sums[idx * d_mul];
        local_sums2[tid] = d_sums2[idx * d_mul];
    } else {
        local_sums[tid] = 0.0f;
        local_sums2[tid] = 0.0f;
    }

    barrier(CLK_LOCAL_MEM_FENCE);

    // Tree reduction
    for (int stride = get_local_size(0) / 2; stride > 0; stride >>= 1) {
        if (tid < stride) {
            local_sums[tid] += local_sums[tid + stride];
            local_sums2[tid] += local_sums2[tid + stride];
        }
        barrier(CLK_LOCAL_MEM_FENCE);
    }

    // Write result
    if (tid == 0) {
        int out_idx = gid * d_mul * get_local_size(0);
        // Ensure we don't write out of bounds if the logic drifts
        if (out_idx < d_Ne || gid == 0) { 
             d_sums[out_idx] = local_sums[0];
             d_sums2[out_idx] = local_sums2[0];
        }
    }
}
